UPDATE J09A_temp
SET ENTSCHEIDUNG = (
  CASE
    WHEN HAUS IN (
      SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09A_temp
        GROUP BY HAUS
      ) WHERE eq_count < 3
    ) THEN 'KSA'
    ELSE 'EVU'
  END
);

UPDATE J09A_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT e."Meter Reading (MR) Doc. No."
  FROM eablg e
  WHERE e.Installation = J09A_temp.ANLAGE
)
WHERE EXISTS (
  SELECT 1 FROM eablg e WHERE e.Installation = J09A_temp.ANLAGE
);

